ST.xhtml:
IF (NOT(__ISVALIDREF(lCANOpenDevice))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lAlarmCANOpenMasterNotOperational.initializeState(NopSelf,'',cACCANOpenMasterNotOperational);
lAlarmCANOpenMasterNotOperational.InitialSeverity := cSeverityWarning;
lAlarmCANOpenMasterNotOperational.SeverityWarningTimeout := T#0S;
lAlarmCANOpenMasterNotOperational.SeverityErrorTimeout := T#100MS;
lAlarmCANOpenMasterNotOperational.SeverityCriticalTimeout := T#5S;

lAlarmCANOpenMasterModulation.initializeState(NopSelf,'',cACCANOpenMasterModulation);
lAlarmCANOpenMasterModulation.pause(); // foobar - what impact does this have, should act as if not connected, ie put all joysticks to zero

lAlarmCANOpenMasterAllowableUp.initializeState(NopSelf,'',cACCANOpenMasterAllowableUp);
lAlarmCANOpenMasterAllowableUp.AllowableSystemState := cSystemStatePreOperational;
lAlarmCANOpenMasterAllowableUp.UpperSystemStateScope := cSystemStatePreOperational;
lAlarmCANOpenMasterAllowableUp.LowerSystemStateScope := cSystemStatePreOperational;
lAlarmCANOpenMasterAllowableUp.Life := 10;
lAlarmCANOpenMasterAllowableUp.InitialSeverity := cSeverityNone;
lAlarmCANOpenMasterAllowableUp.SeverityWarningTimeout := T#250MS;
lAlarmCANOpenMasterAllowableUp.SeverityErrorTimeout := T#1S;
lAlarmCANOpenMasterAllowableUp.SeverityCriticalTimeout := T#5S;	

lVREnabled.initializeValueReference(lEnabled,NopSelf,'Enabled','Enable canopen node','',cValueStyleParameter);
lVRTriggerStart.initializeValueReference(lTriggerStart,NopSelf,'TriggerStart','Trigger NMT message to take canopen node Operational','',cValueStyleTrigger);
lVROverrideConnected.initializeValueReference(lOverrideConnected,NopSelf,'OvrdConnected','Force state of canopen node to show as connected','',cValueStyleParameter);

SUPER^.initialize();

lModulationSystemStateScope := cSystemStateOperational;	
lOperationalSystemStateScope := cSystemStateGoOperational;
lStartSystemStateScope := cSystemStateGoOperational;
lModulationSeverity := cSeverityError;

lHeartbeatCounter.initialize();
lEmergencyCounter.initialize();
lMasterHeartbeat.initialize();

lHeartbeatTimer.initialize();
lHeartbeatTimer.Enable := TRUE;
lHeartbeatTimer.Period := cHeartbeatTimer;

lControllerId := lCANOpenDevice.NodeID;

lNMTStartCounter := 0;
lNMTTimer.Enable := TRUE;
lNMTTimer.Period := T#250MS;

lHeartbeatCounter.reset();
lEmergencyCounter.reset();
lOverflowCounter := 0;

lEmergencyInfo.EMCY_ERROR_CODE := 0;
lEmergencyInfo.ERROR_REGISTER := 0;
lEmergencyInfo.ERROR_FIELD[1] := 0;
lEmergencyInfo.ERROR_FIELD[2] := 0;
lEmergencyInfo.ERROR_FIELD[3] := 0;
lEmergencyInfo.ERROR_FIELD[4] := 0;
lEmergencyInfo.ERROR_FIELD[5] := 0;

SUPER^.operator();

IF (NOT(lEnabled)) THEN
	lNodeState := t_node_state.OPERATIONAL;
	lConnected := TRUE;
	RETURN;
END_IF

lNodeStatePrev := NodeState;
NodeState := LINT_TO_INT(INT_TO_LINT(lCANOpenDevice.State));

IF (((NodeState<>t_node_state.OPERATIONAL) AND (gSystemServices.SystemState.State>=lStartSystemStateScope)) OR
	(lTriggerStart)) THEN
	lTriggerStart := FALSE;
	start();
END_IF

lMasterHeartbeat.operator(); // foobar corrected - impact?
lHeartbeatCounter.operator();
lHeartbeatTimer.operator();

IF (lMasterHeartbeat.HeartbeatFault) THEN

	IF (gSystemServices.SystemState.State>=lOperationalSystemStateScope) THEN
		lAlarmCANOpenMasterNotOperational.trigger(FALSE);

		IF (lHeartbeatTimer.Expired) THEN
			lHeartbeatCounter.register();
		END_IF

		IF ((lAlarmCANOpenMasterNotOperational.Severity>=lModulationSeverity) AND
			(gSystemServices.SystemState.State>=lModulationSystemStateScope)) THEN
			lAlarmCANOpenMasterModulation.trigger(FALSE);
		END_IF
	END_IF

	lAlarmCANOpenMasterAllowableUp.test(FALSE);
ELSE
	lHeartbeatTimer.reset();
END_IF
lConnected := ((NOT(lHeartbeatTimer.Expired)) OR (lOverrideConnected)); // observational only

IF (lMasterState<>CIA405.DEVICE_STATE.OPERATIONAL) THEN
	lAlarmChannelNotOperational.trigger(FALSE);
	lChannelState := cChannelStateStarting;
	reset();
	RETURN;
END_IF

IF ((lEnablePerNodeHandling) AND (NOT(ChildrenOK))) THEN
	lAlarmChannelSlaveFailed.trigger(FALSE);

	IF (lRestartOnNodeState) THEN
		lChannelState := cChannelStateStarting;
		reset();
	END_IF
END_IF

IF (NOT(__ISVALIDREF(lCANOpenManager))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lBusPower.Name := 'BusPower';
registerOperational(ADR(lBusPower));

lAlarmChannelNotGood.initializeState(NopSelf,'',cACChannelNotGood);
lAlarmChannelNotGood.AllowableSystemState := lAllowableUpSystemStateScope;
lAlarmChannelNotGood.UpperSystemStateScope := lAllowableUpSystemStateScope;
lAlarmChannelNotGood.LowerSystemStateScope := lAllowableUpSystemStateScope;
lAlarmChannelNotGood.InitialSeverity := cSeverityWarning;
lAlarmChannelNotGood.SeverityWarningTimeout := T#100MS;
lAlarmChannelNotGood.SeverityErrorTimeout := T#250MS;
lAlarmChannelNotGood.SeverityCriticalTimeout := T#2S;
lAlarmChannelNotGood.ForceTrigger := TRUE;

lAlarmChannelOperationalFail.initializeState(NopSelf,'',cACChannelOperationalFail);
lAlarmChannelOperationalFail.Control := lSystemControlRecovery;
lAlarmChannelOperationalFail.AllowableSystemState := lAllowableUpSystemStateScope;

lAlarmChannelNotOperational.initializeState(NopSelf,'',cACChannelNotOperational);
lAlarmChannelNotOperational.InitialSeverity := cSeverityWarning;
lAlarmChannelNotOperational.SeverityWarningTimeout := T#100MS;
lAlarmChannelNotOperational.SeverityErrorTimeout := T#250MS;
lAlarmChannelNotOperational.SeverityCriticalTimeout := T#1S;

lAlarmChannelOverflow.initializeState(NopSelf,'',cACChannelOverflow);
lAlarmChannelOverflow.InitialSeverity := cSeverityWarning;
lAlarmChannelOverflow.SeverityWarningTimeout := T#100MS;
lAlarmChannelOverflow.SeverityErrorTimeout := T#500MS;
lAlarmChannelOverflow.SeverityCriticalTimeout := T#1S;

lAlarmChannelSlaveFailed.initializeState(NopSelf,'',cACChannelSlaveFailed);
lAlarmChannelSlaveFailed.InitialSeverity := cSeverityWarning;
lAlarmChannelSlaveFailed.SeverityWarningTimeout := T#100MS;
lAlarmChannelSlaveFailed.SeverityErrorTimeout := T#1000MS;
lAlarmChannelSlaveFailed.SeverityCriticalTimeout := T#5S;

SUPER^.initialize();

lBusPower.OutputSystemState := cSystemStateStandby;

lChannelState := cChannelStateStarting;

lGetDeviceState.ENABLE := TRUE;
lGetDeviceState.DEVICE := 0;
lGetDeviceState.TIMEOUT := 200;

lGetKernelState.ENABLE := TRUE;
lGetKernelState.TIMEOUT := 200;

lNMT.DEVICE := 1;
lNMT.ENABLE := TRUE;
lNMT.TIMEOUT := 500;
lNMTStartCounter := 0;
lNMTStartAttemptCounter := 0;

lTransmitNMT.initialize();
lTransmitMessage.initialize();

lCANOpenManager REF= manager;

lGetDeviceState.NETWORK := channel;
lGetKernelState.NETWORK := channel;
lNMT.NETWORK := channel;

lTransmitNMT.initializeMessage(handleTransmitNMT,channel);
lTransmitMessage.initializeMessage(handleTransmitMessage,channel);

IF (NOT(lEnable)) THEN
	lChannelState := cChannelStateGood;
	RETURN;
END_IF

SUPER^.operator();

CASE lChannelState OF
	cChannelStateNone:
		;
	cChannelStateError:
		starting();
	cChannelStateStarting:
		starting();
	cChannelStateGood:
		good();
	cChannelStateOverflow:
		starting();
	cChannelStateHeartbeat:
		starting();
	cChannelStateEmergency:
		starting();
END_CASE

lKernel := lCANOpenManager.KernelState;
lMandatoryBooted := lCANOpenManager.MandatorySlavesBooted;
lOptionalBooted := lCANOpenManager.OptionalSlavesBooted;

lGetDeviceState.ENABLE := TRUE;
lGetDeviceState();
IF (lGetDeviceState.CONFIRM) THEN
	lMasterState := lGetDeviceState.STATE;
END_IF
IF ((lGetDeviceState.CONFIRM) OR (lGetDeviceState.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
	lGetDeviceState.ENABLE := FALSE;
	lGetDeviceState();
END_IF

lGetKernelState.ENABLE := TRUE;
lGetKernelState();
IF (lGetKernelState.CONFIRM) THEN
	lKernelState := lGetKernelState.STATE;
END_IF
IF ((lGetKernelState.CONFIRM) OR (lGetKernelState.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
	lGetKernelState.ENABLE := FALSE;
	lGetKernelState();
END_IF

IF (lChannelState<cChannelStateGood) THEN
	lAlarmChannelNotGood.trigger(FALSE);

	IF (gSystemServices.SystemState.State>=lOperationalSystemStateScope) THEN
		lAlarmChannelOperationalFail.trigger(FALSE);
	END_IF
END_IF

CASE lKernelState OF
	CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_DATA_OVERFLOW:
		overflow();
END_CASE

lAlarmChannelOverflow.report(FALSE);

IF ((lEstopOnOverflow) AND (gSystemServices.SystemState.State=cSystemStateOperational)) THEN
	lAlarmChannelOverflow.propagate(); //foobar should be pause everything due to canbus system health, or go slow on all travel
END_IF

IF (lRestartOnOverflow) THEN
	lChannelState := cChannelStateStarting;
	reset();
END_IF

lNMT.STATE := CIA405.TRANSITION_STATE.RESET_NODE;
lNMT.DEVICE := 1;
lNMT.ENABLE := lNMTEnableStart;
lNMT();
IF ((lNMT.CONFIRM) OR (lNMT.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
	lNMT.ENABLE := FALSE;
	lNMTStartAttemptCounter := lNMTStartAttemptCounter + 1;
	IF (lNMT.CONFIRM) THEN
		lNMTStartCounter := lNMTStartCounter + 1;
	END_IF
	lNMT();
END_IF

IF ((NOT(__ISVALIDREF(lCANRemoteDevice))) OR
	(NOT(__ISVALIDREF(lMaster)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lAlarmCANOpenSlaveNotOperational.initializeState(NopSelf,'',cACCANOpenSlaveNotOperational);
lAlarmCANOpenSlaveNotOperational.InitialSeverity := cSeverityWarning;
lAlarmCANOpenSlaveNotOperational.SeverityWarningTimeout := T#0S;
lAlarmCANOpenSlaveNotOperational.SeverityErrorTimeout := T#100MS;
lAlarmCANOpenSlaveNotOperational.SeverityCriticalTimeout := T#5S;

lAlarmCANOpenSlaveModulation.initializeState(NopSelf,'',cACCANOpenSlaveModulation); // foobar life was zero
lAlarmCANOpenSlaveModulation.pause();

lAlarmCANOpenSlaveAllowableUp.initializeState(NopSelf,'',cACCANOpenSlaveAllowableUp);
lAlarmCANOpenSlaveAllowableUp.AllowableSystemState := cSystemStateGoOperational;
lAlarmCANOpenSlaveAllowableUp.UpperSystemStateScope := cSystemStateGoOperational;
lAlarmCANOpenSlaveAllowableUp.LowerSystemStateScope := cSystemStateGoOperational;
lAlarmCANOpenSlaveAllowableUp.Life := 10;
lAlarmCANOpenSlaveAllowableUp.InitialSeverity := cSeverityNone;
lAlarmCANOpenSlaveAllowableUp.SeverityWarningTimeout := T#250MS;
lAlarmCANOpenSlaveAllowableUp.SeverityErrorTimeout := T#1S;
lAlarmCANOpenSlaveAllowableUp.SeverityCriticalTimeout := T#5S;	

lVREnabled.initializeValueReference(lEnabled,NopSelf,'Enabled','Enable canopen node','',cValueStyleParameter);
lVRTriggerStart.initializeValueReference(lTriggerStart,NopSelf,'TriggerStart','Trigger NMT message to take canopen node Operational','',cValueStyleTrigger);
lVROverrideConnected.initializeValueReference(lOverrideConnected,NopSelf,'OvrdConnected','Force state of canopen node to show as connected','',cValueStyleParameter);

lAlarmCANOpenSlaveNotify.initializeState(NopSelf,'',cACCANOpenSlaveNotify);
lAlarmCANOpenSlaveNotify.Life := 10;
lAlarmCANOpenSlaveNotify.Severity := cSeverityWarning;

lAlarmCANOpenSlaveBlock.initializeState(NopSelf,'',cACCANOpenSlaveBlock);
lAlarmCANOpenSlaveBlock.Life := 10;

lAlarmCANOpenSlaveStop.initializeState(NopSelf,'',cACCANOpenSlaveStop); // foobar life was zero
lAlarmCANOpenSlaveStop.Control := cSystemControlStop; //foobar consider restart
lAlarmCANOpenSlaveStop.AllowableSystemState := cSystemStatePreOperational;

SUPER^.initialize();

lModulationSystemStateScope := cSystemStateOperational;	
lOperationalSystemStateScopeLower := cSystemStateOperational;
lOperationalSystemStateScopeUpper := cSystemStateOperational;
lStartSystemStateScope := cSystemStateGoOperational;
lModulationSeverity := cSeverityError;

lHeartbeatCounter.initialize();
lEmergencyCounter.initialize();

lHeartbeatTimer.initialize();
lHeartbeatTimer.Enable := TRUE;
lHeartbeatTimer.Period := cHeartbeatPeriod;

lNodeStateTimer.initialize();
lNodeStateTimer.Enable := TRUE;
lNodeStateTimer.Period := cNodeStatePeriod;

lCANRemoteDevice.NMTErrorBehaviour := _3SCOS.NMT_ERROR_BEHAVIOUR.RESTART_SLAVE;
lControllerId := lCANRemoteDevice.NodeID;

//lNMT.DEVICE := lControllerId;
//lNMT.ENABLE := TRUE;
//lNMT.NETWORK := lNetworkId;
//lNMT.TIMEOUT := 500;
lNMTStartCounter := 0;
lNMTTimer.Enable := TRUE;
lNMTTimer.Period := T#250MS;
//lNMTStartFailedCounter := 0;

lSDOWrite.DEVICE := lControllerId;
lSDOWrite.CHANNEL := 0;
lSDOWrite.NETWORK := lNetworkId;
lSDOWrite.ENABLE := FALSE;
lSDOWrite.TIMEOUT := 500;
lSDOWrite.MODE := CIA405.SDO_MODE.AUTO;
lSDOWrite.DATA := ADR(lSDOWriteData);

lSDORead.DEVICE := lControllerId;
lSDORead.CHANNEL := 0;
lSDORead.NETWORK := lNetworkId;
lSDORead.ENABLE := FALSE;
lSDORead.TIMEOUT := 500;
lSDORead.MODE := CIA405.SDO_MODE.AUTO;
lSDORead.DATA := ADR(lSDOReadData);

lReceiveEmcy.DEVICE := lControllerId;
lReceiveEmcy.ENABLE := TRUE;
lReceiveEmcy.NETWORK := lNetworkId;
lReceiveEmcy.TIMEOUT := 200;

SUPER^.operator();

IF (NOT(lEnabled)) THEN
	lNodeState := t_node_state.OPERATIONAL;
	lConnected := TRUE;
	RETURN;
END_IF

lNodeStatePrev := NodeState;
NodeState := lCANRemoteDevice.CANopenState;

IF (((NodeState=t_node_state.PRE_OPERATIONAL) AND (gSystemServices.SystemState.State>=lStartSystemStateScope)) OR
	(lTriggerStart)) THEN
	lTriggerStart := FALSE;
	start();
END_IF

IF ((gSystemServices.SystemState.State>=lStartSystemStateScope) AND (gSystemServices.SystemState.State<lOperationalSystemStateScopeLower)) THEN
	startHandler();
END_IF

IF (gSystemServices.SystemState.State<lStartSystemStateScope) THEN
	startResetHandler();
END_IF

IF (lSDOWrite.ENABLE) THEN
	lSDOWrite();
	IF ((lSDOWrite.CONFIRM) OR (lSDOWrite.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDOWrite.ENABLE := FALSE;
		lSDOWriteAttemptCounter := lSDOWriteAttemptCounter + 1;
		IF (lSDOWrite.CONFIRM) THEN
			lSDOWriteSuccessCounter := lSDOWriteSuccessCounter + 1;
		END_IF
	END_IF	
END_IF

IF (lSDORead.ENABLE) THEN
	lSDORead(DATALENGTH:=lSDODReadDataLength);
	IF ((lSDORead.CONFIRM) OR (lSDORead.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDORead.ENABLE := FALSE;
		lSDOReadAttemptCounter := lSDOReadAttemptCounter + 1;
		IF (lSDORead.CONFIRM) THEN
			lSDOReadSuccess := TRUE;
			sdoReadHandler();
			lSDOLastSuccessfulReadData := lSDOReadData;
			lSDOReadSuccessCounter := lSDOReadSuccessCounter + 1;
		END_IF
	END_IF	
END_IF

lHeartbeatCounter.operator();
lHeartbeatTimer.operator();

IF (NodeState<>t_node_state.OPERATIONAL) THEN

	notOperational();

	IF ((gSystemServices.SystemState.State>=lOperationalSystemStateScopeLower) AND
		(gSystemServices.SystemState.State<=lOperationalSystemStateScopeUpper)) THEN
		lAlarmCANOpenSlaveNotOperational.trigger(FALSE);

		IF ((NodeState=t_node_state.NOT_AVAIL) AND 
			(lHeartbeatTimer.Expired)) THEN
			lHeartbeatCounter.register();
		END_IF

		IF ((lAlarmCANOpenSlaveNotOperational.Severity>=lModulationSeverity) AND
			(gSystemServices.SystemState.State>=lModulationSystemStateScope)) THEN
			lAlarmCANOpenSlaveModulation.trigger(FALSE);
		END_IF
	END_IF

	lAlarmCANOpenSlaveAllowableUp.test(FALSE);
ELSE
	lHeartbeatTimer.reset();
END_IF
lConnected := ((NOT(lHeartbeatTimer.Expired)) OR (lOverrideConnected)); // observational only

lReceiveEmcy.ENABLE := TRUE;
lReceiveEmcy();
IF (lReceiveEmcy.CONFIRM) THEN
	lEmergencyCounter.operator();

	IF (lReceiveEmcy.ERRORINFO.EMCY_ERROR_CODE<>0) THEN
		lEmergencyCounter.register();
		lEmergencyInfo := lReceiveEmcy.ERRORINFO;
		IF (gCANPLCBoolA) THEN emergencyHandler(lReceiveEmcy.ERRORINFO); END_IF
	ELSE
		emergencyRegisterClear();
	END_IF

	lEmergencyCode := lReceiveEmcy.ERRORINFO.EMCY_ERROR_CODE;
END_IF
IF ((lReceiveEmcy.CONFIRM) OR (lReceiveEmcy.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
	lReceiveEmcy.ENABLE := FALSE;
	lReceiveEmcy();
END_IF

IF (force) THEN
	cancelSDORead();
END_IF

IF (lSDORead.ENABLE) THEN
	requestSDORead := FALSE;
	RETURN;
END_IF

requestSDORead := TRUE;

lSDORead.ENABLE := TRUE;

lSDORead.INDEX := index;
lSDORead.SUBINDEX := subindex;
lSDODReadDataLength := length;

lSDOReadSuccess := FALSE;

IF (force) THEN
	cancelSDOWrite();
END_IF

IF (lSDOWrite.ENABLE) THEN
	requestSDOWrite := FALSE;
	RETURN;
END_IF

requestSDOWrite := FALSE;

lSDOWrite.ENABLE := TRUE;

lSDOWrite.INDEX := index;
lSDOWrite.SUBINDEX := subindex;
lSDOWrite.DATALENGTH := length;

lSDOWriteData := data;

lNMTTimer.operator();
IF (lNMTTimer.Expired) THEN
	lMaster.TransmitNMT.startNode(lControllerId);
	lNMTStartCounter := lNMTStartCounter + 1;
	lNMTTimer.reset();
END_IF

(*lNMT.STATE := CIA405.TRANSITION_STATE.START_REMOTE_NODE;
IF (lNMTStartFailedCounter>5) THEN
	lNMT.STATE := CIA405.TRANSITION_STATE.STOP_REMOTE_NODE;
END_IF
IF (lNMTStartFailedCounter>10) THEN
	lNMT.STATE := CIA405.TRANSITION_STATE.RESET_NODE;
END_IF
IF (lNMTStartFailedCounter>15) THEN
	lNMT.STATE := CIA405.TRANSITION_STATE.RESET_COMMUNICATION;
END_IF
IF (lNMTStartFailedCounter>20) THEN
	lMaster.restart();
END_IF

lNMT.DEVICE := lControllerId;
lNMT.ENABLE := lNMTEnableStart;
lNMT();
IF ((lNMT.CONFIRM) OR (lNMT.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
	lNMT.ENABLE := FALSE;
	IF (lNMT.CONFIRM) THEN
		lNMTStartCounter := lNMTStartCounter + 1;
		lNMTStartFailedCounter := 0;
	ELSE
		lNMTStartFailedCounter := lNMTStartFailedCounter + 1;
	END_IF
	lNMT();
END_IF
*)

emergencyRegisterAdd := FALSE;

IF (info.EMCY_ERROR_CODE=0) THEN
	RETURN;
END_IF

FOR i:=1 TO lEmergencyCount DO
	IF (lEmergencyRegister[i].EMCY_ERROR_CODE=info.EMCY_ERROR_CODE) THEN
		RETURN;
	END_IF
END_FOR

IF (lEmergencyCount>=cEmergencyRegisterMax) THEN
	gConfigErrorHandler(pMessage:=CONCAT('overflow in emergency register in',lIdentity));
	RETURN;
END_IF

lEmergencyCount := lEmergencyCount + 1;
lEmergencyRegister[lEmergencyCount] := info;
emergencyRegisterAdd := TRUE;

SUPER^.describe(executeContext);

executeContext^.appendPair('node',BYTE_TO_STRING(lControllerId),FALSE,TRUE);

IF (executeContext^.matchOption(cExecuteOptionVerbose)) THEN
	executeContext^.append('"current_emcy": ');
	executeContext^.recordInitiator();

	executeContext^.appendPair('code',WORD_TO_STRING(lEmergencyRegister[i].EMCY_ERROR_CODE),FALSE,FALSE);
	executeContext^.appendPair('register',BYTE_TO_STRING(lEmergencyRegister[i].ERROR_REGISTER),FALSE,TRUE);
	executeContext^.appendPair('field_1',BYTE_TO_STRING(lEmergencyRegister[i].ERROR_FIELD[1]),FALSE,TRUE);
	executeContext^.appendPair('field_2',BYTE_TO_STRING(lEmergencyRegister[i].ERROR_FIELD[2]),FALSE,TRUE);
	executeContext^.appendPair('field_3',BYTE_TO_STRING(lEmergencyRegister[i].ERROR_FIELD[3]),FALSE,TRUE);
	executeContext^.appendPair('field_4',BYTE_TO_STRING(lEmergencyRegister[i].ERROR_FIELD[4]),FALSE,TRUE);
	executeContext^.appendPair('field_5',BYTE_TO_STRING(lEmergencyRegister[i].ERROR_FIELD[5]),FALSE,TRUE);

	executeContext^.recordTerminator();
END_IF

IF (NodeState=t_node_state.OPERATIONAL) THEN
	lNodeStateTimer.reset();
	lNodeState := NodeState;
	RETURN;
END_IF

lNodeStateTimer.operator();

IF ((lNodeState=t_node_state.OPERATIONAL) AND
	(NOT(lNodeStateTimer.Expired))) THEN
	RETURN;
END_IF

lNodeState := NodeState;

SUPER^.initialize();

lSDOReadAttemptCounter := 0;
lSDOReadSuccessCounter := 0;

lSDORead.CHANNEL := 0;
lSDORead.ENABLE := FALSE;
lSDORead.TIMEOUT := 500;
lSDORead.MODE := CIA405.SDO_MODE.AUTO;
lSDORead.DATA := ADR(lSDOReadData);

SUPER^.operator();

IF (lSDORead.ENABLE) THEN
	lSDORead(DATALENGTH:=lSDODReadDataLength);
	IF ((lSDORead.CONFIRM) OR (lSDORead.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDORead.ENABLE := FALSE;
		lSDOReadAttemptCounter := lSDOReadAttemptCounter + 1;
		IF (lSDORead.CONFIRM) THEN
			lSuccess := TRUE;
			lFinished := TRUE;
			lProceed := TRUE;

			sdoReadHandler();
			lSDOReadSuccessCounter := lSDOReadSuccessCounter + 1;

			finish();
			RETURN;
		END_IF
		IF (lSDORead.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR) THEN
			lSuccess := FALSE;
			lFinished := TRUE;
			lProceed := TRUE;

			finish();
			RETURN;
		END_IF
	END_IF	
END_IF

SUPER^.initialize();

lSDOWriteAttemptCounter := 0;
lSDOWriteSuccessCounter := 0;

lSDOWrite.CHANNEL := 0;
lSDOWrite.ENABLE := FALSE;
lSDOWrite.TIMEOUT := 500;
lSDOWrite.MODE := CIA405.SDO_MODE.AUTO;
lSDOWrite.DATA := ADR(lSDOWriteData);

SUPER^.operator();

IF (lSDOWrite.ENABLE) THEN
	lSDOWrite();
	IF ((lSDOWrite.CONFIRM) OR (lSDOWrite.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR)) THEN
		lSDOWrite.ENABLE := FALSE;
		lSDOWriteAttemptCounter := lSDOWriteAttemptCounter + 1;
		IF (lSDOWrite.CONFIRM) THEN
			lSuccess := TRUE;
			lFinished := TRUE;
			lProceed := TRUE;

			lSDOWriteSuccessCounter := lSDOWriteSuccessCounter + 1;

			finish();
			RETURN;
		END_IF
		IF (lSDOWrite.ERROR<>CIA405.CANOPEN_KERNEL_ERROR.CANOPEN_KERNEL_NO_ERROR) THEN
			lSuccess := FALSE;
			lFinished := TRUE;
			lProceed := TRUE;

			finish();
			RETURN;
		END_IF
	END_IF	
END_IF

IF (NOT(__ISVALIDREF(lSecondaryPowerSupply))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lRequestedRunState.MergeOutput := FALSE;
lRequestedRunState.EnumType := cEnumTypeRunState;
lRequestedRunState.initializeValueObjectOp(OpSelf,'ReqRunStt','Requested run state','',cValueStyleConfigurable);

lTargetVoltage.Scaling := 10.0;
lTargetVoltage.Offset := 0;
lTargetVoltage.initializeValueObjectOp(OpSelf,'VoltageReq','Target voltage','',cValueStyleConfigurable);

lVoltage.Scaling := 0.1;
lVoltage.Offset := 0;
lVoltage.initializeValueObjectOp(OpSelf,'VoltageCurr','Measured voltage','',cValueStyleConfigurable);

lCurrent.Scaling := 0.1;
lCurrent.Offset := 0.0;
lCurrent.initializeValueObjectOp(OpSelf,'CurrentCurr','Measured current','',cValueStyleConfigurable);

lTemperature.Scaling := 1.0;
lTemperature.Offset := 0.0;
lTemperature.initializeValueObjectOp(OpSelf,'Temp','Measured temperature','',cValueStyleConfigurable);

lDiagnosticState.initializeValueObjectOp(OpSelf,'Diagnostic','Diagnostic state','',cValueStyleConfigurable);

lStatusInitialization.Index := 0;
lStatusInitialization.initializeValueObjectOp(OpSelf,'Status','If current status is initialized','',cValueStyleConfigurable);
lStatusInitialization.InputReference REF= lDiagnosticState.ValueReference;

lStatusWorking.Index := 1;
lStatusWorking.initializeValueObjectOp(OpSelf,'Working','If current status is working','',cValueStyleConfigurable);
lStatusWorking.InputReference REF= lDiagnosticState.ValueReference;

(*//lFaultHardware.Index := 2; 16#4
//lFaultFan.Index := 6;16#40
//lFaultHVIL.Index := 7;16#80
lAlarmSecondaryHardware.initializeStateOp(OpSelf,cACSecondaryHardware);
lAlarmSecondaryHardware.Life := 10;
lAlarmSecondaryHardware.Severity := cSeverityCritical;
lAlarmSecondaryHardware.Mask := 16#C4;
lAlarmSecondaryHardware.InputReference REF= lDiagnosticState.ValueReference;

