lAlarmSecondaryCANBus.Life := 10;
lAlarmSecondaryCANBus.Severity := cSeverityCritical;
lAlarmSecondaryCANBus.Mask := 16#8;
lAlarmSecondaryCANBus.InputReference REF= lDiagnosticState.ValueReference;

//lFaultShutdown.Index := 5;16#20
lAlarmSecondaryShutdown.initializeStateOp(OpSelf,cACSecondaryShutdown);
lAlarmSecondaryShutdown.Life := 10;
lAlarmSecondaryShutdown.Severity := cSeverityCritical;
lAlarmSecondaryShutdown.Mask := 16#20;
lAlarmSecondaryShutdown.InputReference REF= lDiagnosticState.ValueReference;

//lWarningTemperature.Index := 8;16#100
//lFaultTemperature.Index := 9;16#200
lAlarmSecondaryTemperature.initializeStateOp(OpSelf,cACSecondaryTemperature);
lAlarmSecondaryTemperature.Life := 10;
lAlarmSecondaryTemperature.Severity := cSeverityWarning;
lAlarmSecondaryTemperature.Mask := 16#300;
lAlarmSecondaryTemperature.InputReference REF= lDiagnosticState.ValueReference;

//lFaultInputOverVoltage.Index := 10;// 16#400
//lFaultInputUnderVoltage.Index := 11;16#800
