lAlarmSecondaryTemperature.initializeState(NopSelf,'',cACSecondaryTemperature);
lAlarmSecondaryTemperature.registerServer(lSecondaryPowerSupply.Modulation);

lCurrentRunState.EnumType := cEnumTypeRunState;
lCurrentRunState.initializeValueObject(NopSelf,'CurrRunStt','Current run state','',cValueStyleConfigurable);

SUPER^.initialize();
SubSystem := cSubsystemSecondary;

lAlarmCANOpenSlaveNotOperational.InitialSeverity := cSeverityNone;
lAlarmCANOpenSlaveNotOperational.SeverityWarningTimeout := T#250MS;
lAlarmCANOpenSlaveNotOperational.SeverityErrorTimeout := T#1S;
lAlarmCANOpenSlaveNotOperational.SeverityCriticalTimeout := T#5S;

lAlarmCANOpenSlaveAllowableUp.AllowableSystemState := cSystemStatePreparing;
lAlarmCANOpenSlaveAllowableUp.UpperSystemStateScope := cSystemStatePreparing;
lAlarmCANOpenSlaveAllowableUp.LowerSystemStateScope := cSystemStatePreparing;

lStartSystemStateScope := t_system_state.cSystemStatePreparing;
lOperationalSystemStateScopeLower := t_system_state.cSystemStateCharging;
lModulationSystemStateScope := t_system_state.cSystemStateCharging;

SUPER^.operator();

IF (NOT(lEnabled)) THEN
	lCurrentRunState.Override := TRUE;
	lCurrentRunState.OverrideValue := cRunStateStart;

	RETURN;
END_IF

IF ((lStatusInitialization.Value) AND
	(lStatusWorking.Value)) THEN
	lCurrentRunState.Value := cRunStateStart;
ELSE	
	lCurrentRunState.Value := cRunStateStop;
END_IF

IF (WORD_TO_BOOL(UINT_TO_WORD(lDiagnosticState.Value) AND 16#7FEC)) THEN
	lAlarmCANOpenSlaveNotify.triggerWithContext(UINT_TO_WORD(lDiagnosticState.Value));
END_IF

IF (WORD_TO_BOOL(UINT_TO_WORD(lDiagnosticState.Value) AND 16#100)) THEN
	lAlarmSecondaryTemperature.ThresholdPositive := cAvailabilityTemperatureWarning;
	lAlarmSecondaryTemperature.trigger(FALSE);
END_IF
IF (WORD_TO_BOOL(UINT_TO_WORD(lDiagnosticState.Value) AND 16#200)) THEN
	lAlarmSecondaryTemperature.ThresholdPositive := cAvailabilityTemperatureFault;
	lAlarmSecondaryTemperature.trigger(FALSE);
END_IF

lVoltage.InputReference REF= voltage;
lCurrent.InputReference REF= current;
lTemperature.InputReference REF= temperature;

lDiagnosticState.InputReference REF= state;

lRequestedRunState.OutputReference REF= control;
lTargetVoltage.OutputReference REF= targetVoltage;

lVREnableDetectionTPDO.initializeValueReference(lEnableDetectionTPDO,NopSelf,'EnblDtctTPDO','Use TPDO traffic to determine node state','',cValueStyleParameter);
lVREnableValidTransmissions.initializeValueReference(lEnableValidTransmissions,NopSelf,'EnblVldTrnms','Check if TPDO traffic is valid','',cValueStyleParameter);

lAlarmCANOpenSlaveNoValidTransmissions.initializeState(NopSelf,'',cACCANOpenSlaveNoValidTransmissions);
lAlarmCANOpenSlaveNoValidTransmissions.AllowableSystemState := cSystemStatePreparing;
lAlarmCANOpenSlaveNoValidTransmissions.UpperSystemStateScope := cSystemStatePreparing;
lAlarmCANOpenSlaveNoValidTransmissions.LowerSystemStateScope := cSystemStatePreparing;
lAlarmCANOpenSlaveNoValidTransmissions.Life := 10;
lAlarmCANOpenSlaveNoValidTransmissions.InitialSeverity := cSeverityNone;
lAlarmCANOpenSlaveNoValidTransmissions.SeverityWarningTimeout := T#2S;
lAlarmCANOpenSlaveNoValidTransmissions.SeverityErrorTimeout := T#4S;
lAlarmCANOpenSlaveNoValidTransmissions.SeverityCriticalTimeout := T#10S;	

SUPER^.initialize();

lNMTDetectionTimer.initialize();
lNMTDetectionTimer.Enable := TRUE;
lNMTDetectionTimer.Period := cNMTDetectionPeriod;

SUPER^.operator();

lTPDO1StuffingPrevious := lTPDO1Stuffing;
lTPDO1Stuffing := Peripheral.TPDO1Stuffing;

IF (NOT(ValidTransmissions)) THEN
	lAlarmCANOpenSlaveNoValidTransmissions.test(FALSE);
END_IF

IF (lEnableDetectionTPDO) THEN

	IF (lTPDO1StuffingPrevious<>lTPDO1Stuffing) THEN
		lNMTDetectionTimer.reset();
	END_IF

	lNMTDetectionTimer.operator();
	IF (NOT(lNMTDetectionTimer.Expired)) THEN
		lNodeState := NodeState;

		IF (lEnableNMTDetectionTPDO) THEN
			lNodeState := t_node_state.OPERATIONAL;
		END_IF

		RETURN;
	END_IF

	IF (lEnableNMTOverrideTPDO) THEN
		lNodeState := t_node_state.NOT_AVAIL;
		RETURN;
	END_IF	
END_IF

lNodeState := NodeState;

IF (NOT(lEnableValidTransmissions)) THEN
	ValidTransmissions := TRUE;
	RETURN;
END_IF

ValidTransmissions := ((NodeState=t_node_state.OPERATIONAL) AND
	(Peripheral.ValidTransmissions));

IF ((NOT(__ISVALIDREF(lControllerSecondaryPowerSupplyA))) OR
	(NOT(__ISVALIDREF(lControllerSecondaryPowerSupplyB)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lAlarmSecondaryNotRunning.initializeState(NopSelf,'',cACSecondaryNotRunning); // foobar escalates to pause
lAlarmSecondaryNotRunning.Life := 10;
lAlarmSecondaryNotRunning.InitialSeverity := cSeverityNone;
lAlarmSecondaryNotRunning.SeverityWarningTimeout := T#1S;
lAlarmSecondaryNotRunning.SeverityErrorTimeout := T#2S;
lAlarmSecondaryNotRunning.SeverityCriticalTimeout := T#5S;

lAlarmSecondaryNotRunningModulation.initializeState(NopSelf,'',cACSecondaryNotRunningModulation); // foobar life was zero
lAlarmSecondaryNotRunningModulation.pause();
lAlarmSecondaryNotRunningModulation.registerServer(ADR(lModulation));

lAlarmSecondaryWaiting.initializeState(NopSelf,'',cACSecondaryWaiting);
lAlarmSecondaryWaiting.AllowableSystemState := cSystemStatePreparing;
lAlarmSecondaryWaiting.UpperSystemStateScope := cSystemStatePreparing;
lAlarmSecondaryWaiting.LowerSystemStateScope := cSystemStatePreparing;
lAlarmSecondaryWaiting.Life := 10;
lAlarmSecondaryWaiting.InitialSeverity := cSeverityNone;
lAlarmSecondaryWaiting.SeverityWarningTimeout := T#1S;
lAlarmSecondaryWaiting.SeverityErrorTimeout := T#2S;
lAlarmSecondaryWaiting.SeverityCriticalTimeout := T#5S;

lAlarmRunStateMismatch.initializeState(NopSelf,'',cACSecondaryRunStateMismatch);
lAlarmRunStateMismatch.InitialSeverity := cSeverityNone;
lAlarmRunStateMismatch.SeverityWarningTimeout := T#2S;
lAlarmRunStateMismatch.SeverityErrorTimeout := T#4S;
lAlarmRunStateMismatch.SeverityCriticalTimeout := T#6S;

lModulation.initializeEvent(NopSelf,'',cECSecondaryPowerModulation);

SUPER^.initialize();
SubSystem := cSubsystemSecondary;

lModulationSeverity := cSeverityError;
lTargetVoltage := cSecondaryTargetVoltage;

lStartDelayTimer.Enable := TRUE;
lStartDelayTimer.Period := cStartDelayPeriod;
lStartDelayTimer.initialize();

lCurrentState := cRunStateNone;

IF ((lControllerSecondaryPowerSupplyA.CurrentRunState=cRunStateStop) OR
	(lControllerSecondaryPowerSupplyB.CurrentRunState=cRunStateStop)) THEN
	lCurrentState := cRunStateStop;
END_IF

IF ((lControllerSecondaryPowerSupplyA.CurrentRunState=cRunStateStart) AND
	(lControllerSecondaryPowerSupplyB.CurrentRunState=cRunStateStart)) THEN
	lCurrentState := cRunStateStart;
END_IF

IF (lControllerSecondaryPowerSupplyA.CurrentRunState<>lControllerSecondaryPowerSupplyB.CurrentRunState) THEN
	lAlarmRunStateMismatch.trigger(FALSE); // foobar any further action
END_IF

SUPER^.operator();

lRequestedState := cRunStateStop;
lAvailability := 0.0;

IF (gSystemServices.SystemState.State<cSystemStatePreparing) THEN
	RETURN;
END_IF

IF (BMSConnected) THEN
	lRequestedState := cRunStateStart;
ELSE
	lStartDelayTimer.reset();	
END_IF
lStartDelayTimer.operator();

IF (lCurrentState<>cRunStateStart) THEN
	lAlarmSecondaryNotRunning.trigger(FALSE);

	IF (lAlarmSecondaryNotRunning.Severity>=lModulationSeverity) THEN
		lAlarmSecondaryNotRunningModulation.trigger(FALSE);
	END_IF

	lAlarmSecondaryWaiting.test(FALSE);	
END_IF

lModulation.operator();
lAvailability := MIN(lModulation.ScalingPositive,lModulation.ThresholdPositive);

lControllerSecondaryPowerSupplyA.RequestedRunState := lRequestedState;
IF ((lStartDelayTimer.Expired) AND (lRequestedState=cRunStateStart)) THEN
	lControllerSecondaryPowerSupplyB.RequestedRunState := cRunStateStart;
ELSE
	lControllerSecondaryPowerSupplyB.RequestedRunState := cRunStateStop;	
END_IF

lControllerSecondaryPowerSupplyA.TargetVoltage := lTargetVoltage;
lControllerSecondaryPowerSupplyB.TargetVoltage := lTargetVoltage;
